-- ************************************** ANALYTICS.VW_PATIENT_ENCOUNTER_SUMMARY
CREATE SECURE VIEW ANALYTICS.VW_PATIENT_ENCOUNTER_SUMMARY
(
  ENCOUNTER_KEY,
  ENCOUNTER_ID,
  PATIENT_KEY,
  PATIENT_ID,
  FIRST_NAME,
  LAST_NAME,
  DATE_OF_BIRTH,
  GENDER,
  PROVIDER_KEY,
  PROVIDER_ID,
  PROVIDER_NAME,
  SPECIALTY,
  FACILITY_KEY,
  FACILITY_ID,
  FACILITY_NAME,
  FACILITY_TYPE,
  DEPARTMENT_KEY,
  DEPARTMENT_ID,
  DEPARTMENT_NAME,
  SERVICE_LINE,
  LOCATION_KEY,
  LOCATION_ID,
  LOCATION_NAME,
  PAYER_PLAN_KEY,
  PAYER_PLAN_ID,
  PAYER_NAME,
  PLAN_NAME,
  INSURANCE_COVERAGE_KEY,
  COVERAGE_TIER,
  ADMIT_DATE,
  DISCHARGE_DATE,
  ENCOUNTER_TYPE,
  ENCOUNTER_CLASS,
  LENGTH_OF_STAY_DAYS,
  TOTAL_CHARGES_AMOUNT,
  TOTAL_PAYMENTS_AMOUNT,
  EADMISSION_FLAG,
  WRITE_OFF_AMOUNT,
  CREATED_TIMESTAMP,
  CREATED_BY_NAME,
  UPDATED_TIMESTAMP,
  UPDATED_BY_NAME
)
CHANGE_TRACKING = FALSE
AS
SELECT 
    e.ENCOUNTER_KEY,
    e.ENCOUNTER_ID,
    p.PATIENT_KEY,
    p.PATIENT_ID,
    p.FIRST_NAME,
    p.LAST_NAME,
    p.DATE_OF_BIRTH,
    p.GENDER,
    pr.PROVIDER_KEY,
    pr.PROVIDER_ID,
    pr.PROVIDER_NAME,
    pr.SPECIALTY,
    f.FACILITY_KEY,
    f.FACILITY_ID,
    f.FACILITY_NAME,
    f.FACILITY_TYPE,
    d.DEPARTMENT_KEY,
    d.DEPARTMENT_ID,
    d.DEPARTMENT_NAME,
    d.SERVICE_LINE,
    l.LOCATION_KEY,
    l.LOCATION_ID,
    l.LOCATION_NAME,
    pp.PAYER_PLAN_KEY,
    pp.PAYER_PLAN_ID,
    pp.PAYER_NAME,
    pp.PLAN_NAME,
    ic.INSURANCE_COVERAGE_KEY,
    ic.COVERAGE_TIER,
    dd_admit.CALENDAR_DATE AS ADMIT_DATE,
    dd_discharge.CALENDAR_DATE AS DISCHARGE_DATE,
    e.ENCOUNTER_TYPE,
    e.ENCOUNTER_CLASS,
    e.LENGTH_OF_STAY_DAYS,
    e.TOTAL_CHARGES_AMOUNT,
    e.TOTAL_PAYMENTS_AMOUNT,
    e.READMISSION_FLAG,
    (e.TOTAL_CHARGES_AMOUNT - e.TOTAL_PAYMENTS_AMOUNT) AS WRITE_OFF_AMOUNT
FROM ANALYTICS.FACT_ENCOUNTER e
LEFT JOIN ANALYTICS.DIM_PATIENT p ON e.PATIENT_KEY = p.PATIENT_KEY AND p.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_PROVIDER pr ON e.PROVIDER_KEY = pr.PROVIDER_KEY AND pr.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_FACILITY f ON e.FACILITY_KEY = f.FACILITY_KEY AND f.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_DEPARTMENT d ON e.DEPARTMENT_KEY = d.DEPARTMENT_KEY
LEFT JOIN ANALYTICS.DIM_LOCATION l ON e.LOCATION_KEY = l.LOCATION_KEY
LEFT JOIN ANALYTICS.DIM_PAYER_PLAN pp ON e.PAYER_PLAN_KEY = pp.PAYER_PLAN_KEY AND pp.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_INSURANCE_COVERAGE ic ON e.INSURANCE_COVERAGE_KEY = ic.INSURANCE_COVERAGE_KEY AND ic.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_DATE dd_admit ON e.ADMIT_DATE_KEY = dd_admit.DATE_KEY
LEFT JOIN ANALYTICS.DIM_DATE dd_discharge ON e.DISCHARGE_DATE_KEY = dd_discharge.DATE_KEY;

